// components/particles/LogisticsParticles.jsx
import { useEffect, useState } from "react";
import Particles, { initParticlesEngine } from "@tsparticles/react";
import { loadSlim } from "tsparticles-slim";

// Синглтон — инициализируется ОДИН РАЗ за всё время жизни приложения
let engineReady = false;
let enginePromise = null;

function getEngine() {
  if (!enginePromise) {
    enginePromise = initParticlesEngine(async (engine) => {
      await loadSlim(engine);
    }).then(() => {
      engineReady = true;
    });
  }
  return enginePromise;
}

export default function LogisticsParticles() {
  const [init, setInit] = useState(engineReady);

  useEffect(() => {
    if (engineReady) return;
    getEngine().then(() => setInit(true));
  }, []);

  const options = {
    fullScreen: { enable: false },
    background: { color: "transparent" },
    fpsLimit: 60,

    particles: {
      number: { value: 100, density: { enable: true, area: 900 } },

      color: { value: ["#15803d", "#16a34a", "#4ade80", "#22c55e", "#ffffff"] },

      shape: { type: "circle" },

      opacity: {
        value: { min: 0.5, max: 1 },
        animation: { enable: true, speed: 0.6, sync: false },
      },

      size: { value: { min: 3, max: 7 } },

      links: {
        enable: true,
        distance: 150,
        color: "#15803d",
        opacity: 0.6,       // более яркие линии-дороги
        width: 1.5,
      },

      move: {
        enable: true,
        speed: { min: 1, max: 3.5 },
        direction: "none",
        random: true,
        outModes: { default: "out" },
      },
    },

    interactivity: {
      events: {
        onHover: { enable: true, mode: "grab" },
        onClick: { enable: true, mode: "push" },
      },
      modes: {
        grab: { distance: 160, links: { opacity: 1 } },
        push: { quantity: 4 },
      },
    },

    detectRetina: true,
  };

  if (!init) return null;

  return (
    <Particles
      id="logistics-particles"
      options={options}
      style={{
        position: "absolute",
        inset: 0,
        width: "100%",
        height: "100%",
        zIndex: 0,
      }}
    />
  );
}
